#include <omp.h>
#include <stdio.h>
#include <stdlib.h>

#include "../common.h"
#include "../util/timer/timer.h"
#include "./kernel_cpu.h"

//========================================================================================================================================================================================================200
//	KERNEL
//========================================================================================================================================================================================================200

void
findK(	long height,
		knode *knodes,
		long knodes_elem,
		long *currKnode,
		long *offset,
		int *keys,
		record *records,
		record *ans,
		int count)
{
	// process levels of the tree
	for(int i = 0; i < height; i++){
		#pragma omp parallel for schedule(static)
		for(int bid = 0; bid < count; bid++){
			int current_node_idx = currKnode[bid];
			int num_keys_in_node = knodes[current_node_idx].num_keys;

			int found_thid = -1;
			// Binary search for the key range
			int low = 0, high = num_keys_in_node;
			while(low <= high){
				int mid = low + (high - low) / 2;
				if(mid < num_keys_in_node && keys[bid] >= knodes[current_node_idx].keys[mid]){
					if(mid + 1 <= num_keys_in_node && keys[bid] < knodes[current_node_idx].keys[mid+1]){
						found_thid = mid;
						break;
					} else {
						low = mid + 1;
					}
				} else {
					high = mid - 1;
				}
			}
			// Handle edge case where key is greater than or equal to the last key
			if (found_thid == -1 && num_keys_in_node > 0 && keys[bid] >= knodes[current_node_idx].keys[num_keys_in_node-1]) {
				found_thid = num_keys_in_node -1; // This might need adjustment based on exact B+ tree logic for last key
			}
			// If still not found, it might be the first element or outside range
			if (found_thid == -1 && num_keys_in_node > 0 && keys[bid] < knodes[current_node_idx].keys[0]) {
				// This case should ideally not happen if keys are properly distributed,
				// but for completeness, we might need to assign to the first child.
				// For now, we assume keys[bid] will fall into one of the ranges.
			}
			// If the key is larger than all keys in the node, it should go to the last child.
			if (found_thid == -1 && num_keys_in_node > 0 && keys[bid] >= knodes[current_node_idx].keys[num_keys_in_node-1]) {
				found_thid = num_keys_in_node -1; // This logic needs to be precise for B+ tree.
			}


			if(found_thid != -1){
				if(knodes_elem > knodes[current_node_idx].indices[found_thid]){
					offset[bid] = knodes[current_node_idx].indices[found_thid];
				}
			}
		}

		// synchronize threads
		#pragma omp barrier

		// set for next tree level
		#pragma omp parallel for schedule(static)
		for(int bid = 0; bid < count; bid++){
			currKnode[bid] = offset[bid];
		}

		#pragma omp barrier
	}

	// At this point, we have a candidate leaf node which may contain
	// the target record.  Check each key to hopefully find the record
	#pragma omp parallel for schedule(static)
	for(int bid = 0; bid < count; bid++){
		int current_node_idx = currKnode[bid];
		int num_keys_in_node = knodes[current_node_idx].num_keys;

		// Find the correct 'thid' (index within the node's keys)
		int found_thid = -1;
		for (int k = 0; k < num_keys_in_node; ++k) {
			if(knodes[current_node_idx].keys[k] == keys[bid]){
				found_thid = k;
				break;
			}
		}

		if (found_thid != -1) {
			ans[bid].value = records[knodes[current_node_idx].indices[found_thid]].value;
		}
	}
}

//========================================================================================================================================================================================================200
//	WRAPPER FUNCTION
//========================================================================================================================================================================================================200

void
kernel_cpu(int cores_arg,
		   record *records,
		   knode *knodes,
		   long knodes_elem,
		   long knodes_mem, // Not used in CPU version, but kept for signature consistency

		   int order,
		   long maxheight,
		   int count,

		   long *currKnode,
		   long *offset,
		   int *keys,
		   record *ans)
{
	//======================================================================================================================================================150
	//	Variables
	//======================================================================================================================================================150

	// timer
	long long time0;
	long long time1;
	long long time2;
	long long time3;
	long long time4;
	long long time5;
	long long time6;

	time0 = get_time();

	//======================================================================================================================================================150
	//	CPU SETUP
	//======================================================================================================================================================150

	// Set the number of OpenMP threads
	if (cores_arg > 0) {
		omp_set_num_threads(cores_arg);
	} else {
		// Default to a reasonable number of threads if cores_arg is not specified or invalid
		int num_cores = omp_get_max_threads();
		omp_set_num_threads(num_cores > 0 ? num_cores : 1);
	}

	time1 = get_time();

	//======================================================================================================================================================150
	//	MEMORY ALLOCATION (Not needed for CPU version as data is already on host)
	//======================================================================================================================================================150
	time2 = get_time();

	//======================================================================================================================================================150
	//	MEMORY COPY (Not needed for CPU version as data is already on host)
	//======================================================================================================================================================150
	time3 = get_time();

	//======================================================================================================================================================150
	//	KERNEL EXECUTION PARAMETERS
	//======================================================================================================================================================150

	// threads per block is not directly applicable in OpenMP in the same way as CUDA.
	// The number of threads is managed by the runtime.
	// blocks per grid is also not directly applicable. The parallel loops handle this.

	printf("# of blocks = %d, # of threads/block = %d\n", count, omp_get_max_threads());

	time4 = get_time();

	//======================================================================================================================================================150
	//	KERNEL
	//======================================================================================================================================================150

	findK(	maxheight,
			knodes,
			knodes_elem,
			currKnode,
			offset,
			keys,
			records,
			ans,
			count);

	time5 = get_time();

	//======================================================================================================================================================150
	//	COPY RESULTS BACK TO CPU (Not needed for CPU version as data is already on host)
	//======================================================================================================================================================150
	time6 = get_time();

	//======================================================================================================================================================150
	//	DISPLAY TIMING
	//======================================================================================================================================================150

	printf("Time spent in different stages of CPU KERNEL:\n");

	printf("%15.12f s, %15.12f % : CPU: SET DEVICE / DRIVER INIT\n",	(float) (time1-time0) / 1000000, (float) (time1-time0) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f % : CPU: ALLOCATE GPU MEMORY\n", 		(float) (time2-time1) / 1000000, (float) (time2-time1) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f % : CPU: COPY DATA TO GPU\n", 			(float) (time3-time2) / 1000000, (float) (time3-time2) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f % : CPU: PROCESSING\n", 				(float) (time4-time3) / 1000000, (float) (time4-time3) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f % : CPU: KERNEL\n", 					(float) (time5-time4) / 1000000, (float) (time5-time4) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f % : CPU: COPY DATA FROM GPU\n", 		(float) (time6-time5) / 1000000, (float) (time6-time5) / (float) (time6-time0) * 100);

	printf("Total time:\n");
	printf("%.12f s\n", 												(float) (time6-time0) / 1000000);

	//======================================================================================================================================================150
	//	FREE MEMORY (Not needed for CPU version)
	//======================================================================================================================================================150
}

