void
findRangeK(	long height,
			knode *knodes,
			long knodes_elem,
			long *currKnode,
			long *offset,
			long *lastKnode,
			long *offset_2,
			int *start,
			int *end,
			int *recstart,
			int *reclength,
			int count)
{
	// process levels of the tree
	for(int i = 0; i < height; i++){
		#pragma omp parallel for schedule(static)
		for(int bid = 0; bid < count; bid++){
			int current_node_idx_start = currKnode[bid];
			int num_keys_in_node_start = knodes[current_node_idx_start].num_keys;

			int found_thid_start = -1;
			// Binary search for the start key range
			int low_s = 0, high_s = num_keys_in_node_start;
			while(low_s <= high_s){
				int mid_s = low_s + (high_s - low_s) / 2;
				if(mid_s < num_keys_in_node_start && start[bid] >= knodes[current_node_idx_start].keys[mid_s]){
					if(mid_s + 1 <= num_keys_in_node_start && start[bid] < knodes[current_node_idx_start].keys[mid_s+1]){
						found_thid_start = mid_s;
						break;
					} else {
						low_s = mid_s + 1;
					}
				} else {
					high_s = mid_s - 1;
				}
			}
			if (found_thid_start == -1 && num_keys_in_node_start > 0 && start[bid] >= knodes[current_node_idx_start].keys[num_keys_in_node_start-1]) {
				found_thid_start = num_keys_in_node_start -1;
			}


			if(found_thid_start != -1){
				if(knodes[current_node_idx_start].indices[found_thid_start] < knodes_elem){
					offset[bid] = knodes[current_node_idx_start].indices[found_thid_start];
				}
			}

			// Process for end key
			int current_node_idx_end = lastKnode[bid];
			int num_keys_in_node_end = knodes[current_node_idx_end].num_keys;

			int found_thid_end = -1;
			// Binary search for the end key range
			int low_e = 0, high_e = num_keys_in_node_end;
			while(low_e <= high_e){
				int mid_e = low_e + (high_e - low_e) / 2;
				if(mid_e < num_keys_in_node_end && end[bid] >= knodes[current_node_idx_end].keys[mid_e]){
					if(mid_e + 1 <= num_keys_in_node_end && end[bid] < knodes[current_node_idx_end].keys[mid_e+1]){
						found_thid_end = mid_e;
						break;
					} else {
						low_e = mid_e + 1;
					}
				} else {
					high_e = mid_e - 1;
				}
			}
			if (found_thid_end == -1 && num_keys_in_node_end > 0 && end[bid] >= knodes[current_node_idx_end].keys[num_keys_in_node_end-1]) {
				found_thid_end = num_keys_in_node_end -1;
			}

			if(found_thid_end != -1){
				if(knodes[current_node_idx_end].indices[found_thid_end] < knodes_elem){
					offset_2[bid] = knodes[current_node_idx_end].indices[found_thid_end];
				}
			}
		}

		// synchronize threads
		#pragma omp barrier

		// set for next tree level
		#pragma omp parallel for schedule(static)
		for(int bid = 0; bid < count; bid++){
			currKnode[bid] = offset[bid];
			lastKnode[bid] = offset_2[bid];
		}

		#pragma omp barrier
	}

	// process leaves
	// Find the index of the starting record
	#pragma omp parallel for schedule(static)
	for(int bid = 0; bid < count; bid++){
		int current_node_idx = currKnode[bid];
		int num_keys_in_node = knodes[current_node_idx].num_keys;

		for (int k = 0; k < num_keys_in_node; ++k) {
			if(knodes[current_node_idx].keys[k] == start[bid]){
				recstart[bid] = knodes[current_node_idx].indices[k];
				break;
			}
		}
	}

	#pragma omp barrier

	// Find the index of the ending record
	#pragma omp parallel for schedule(static)
	for(int bid = 0; bid < count; bid++){
		int current_node_idx = lastKnode[bid];
		int num_keys_in_node = knodes[current_node_idx].num_keys;

		for (int k = 0; k < num_keys_in_node; ++k) {
			if(knodes[current_node_idx].keys[k] == end[bid]){
				reclength[bid] = knodes[current_node_idx].indices[k] - recstart[bid] + 1;
				break;
			}
		}
	}
}

